// src/components/BookPage.jsx
// Renders a single page inside the flipbook.

export default function BookPage({ page, pageNum, total, onShowRef }) {
  const isCover = page.type === "cover";
  const isEnd = page.type === "end";

  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        background: page.bg || "#fff",
        color: page.textColor || "#333",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: "28px 24px",
        boxSizing: "border-box",
        fontFamily: "'Bubblegum Sans', cursive",
        position: "relative",
        overflow: "hidden",
        userSelect: "none",
      }}
    >
      {/* decorative circles */}
      <div style={{
        position: "absolute", top: -40, left: -40, width: 120, height: 120,
        borderRadius: "50%", background: "rgba(255,255,255,0.12)", pointerEvents: "none",
      }} />
      <div style={{
        position: "absolute", bottom: -30, right: -30, width: 90, height: 90,
        borderRadius: "50%", background: "rgba(255,255,255,0.10)", pointerEvents: "none",
      }} />

      {/* big emoji */}
      <div style={{ fontSize: isCover || isEnd ? 72 : 56, lineHeight: 1, marginBottom: 10 }}>
        {page.image || "📖"}
      </div>

      {/* title */}
      <div style={{
        fontSize: page.titleSize || (isCover || isEnd ? page.fontSize || 30 : 22),
        fontWeight: 800,
        textAlign: "center",
        lineHeight: 1.2,
        marginBottom: 8,
        textShadow: "0 2px 8px rgba(0,0,0,0.15)",
        letterSpacing: isCover ? "0.04em" : "0.01em",
      }}>
        {page.title}
      </div>

      {/* subtitle */}
      {(isCover || isEnd) && page.subtitle && (
        <div style={{
          fontSize: 16, opacity: 0.9, textAlign: "center",
          marginBottom: 12, fontStyle: "italic",
        }}>
          {page.subtitle}
        </div>
      )}

      {/* body text */}
      {page.text && (
        <div style={{
          fontSize: page.fontSize || 16,
          textAlign: "center",
          lineHeight: 1.7,
          maxWidth: 280,
          marginTop: 8,
          background: "rgba(255,255,255,0.25)",
          borderRadius: 16,
          padding: "12px 16px",
          backdropFilter: "blur(4px)",
        }}>
          {page.text}
        </div>
      )}

      {/* accent emoji */}
      {page.emoji && (
        <div style={{ fontSize: 40, marginTop: 16 }}>{page.emoji}</div>
      )}

      {/* 🔍 Reference button */}
      {page.reference && onShowRef && (
        <button
          onClick={onShowRef}
          title={`Learn about: ${page.reference.title}`}
          style={{
            position: "absolute",
            top: 10,
            left: 10,
            background: "rgba(255,255,255,0.25)",
            border: "1px solid rgba(255,255,255,0.5)",
            borderRadius: 20,
            padding: "4px 10px",
            cursor: "pointer",
            fontSize: 11,
            fontWeight: 700,
            fontFamily: "'Nunito',sans-serif",
            color: page.textColor || "#333",
            backdropFilter: "blur(4px)",
            display: "flex",
            alignItems: "center",
            gap: 4,
            transition: "all 0.2s",
          }}
        >
          🔍 Learn
        </button>
      )}

      {/* page number */}
      {!isCover && (
        <div style={{
          position: "absolute", bottom: 10,
          fontSize: 12, opacity: 0.6,
          fontFamily: "'Nunito', sans-serif",
        }}>
          {pageNum} / {total}
        </div>
      )}

      {/* stars for cover/end */}
      {(isCover || isEnd) && (
        <div style={{
          position: "absolute", top: 10, right: 10,
          fontSize: 22, opacity: 0.7, letterSpacing: 4,
        }}>
          ⭐🌟⭐
        </div>
      )}
    </div>
  );
}
